public final class WSActionAnnotator implements Annotator { private static final QName WSAW_ACTION_QNAME = new QName ( "http://www.w3.org/2006/05/addressing/wsdl" , "Action" ) ; private static final QName WSAM_ACTION_QNAME = new QName ( "http://www.w3.org/2007/05/addressing/metadata" , "Action" ) ; private static final QName WSAW_OLD_ACTION_QNAME = new QName ( "http://www.w3.org/2005/02/addressing/wsdl" , "Action" ) ; private OperationInfo operation ; public WSActionAnnotator ( final OperationInfo op ) { this . operation = op ; } private String getAction ( AbstractMessageContainer mi ) { QName action = ( QName ) mi . getExtensionAttribute ( WSAW_ACTION_QNAME ) ; if ( action == null ) { action = ( QName ) mi . getExtensionAttribute ( WSAM_ACTION_QNAME ) ; } if ( action == null ) { action = ( QName ) mi . getExtensionAttribute ( WSAW_OLD_ACTION_QNAME ) ; } if ( action != null ) { String s = action . getLocalPart ( ) ; if ( ! StringUtils . isEmpty ( s ) ) { return s ; } } return null ; } public void annotate ( JavaAnnotatable ja ) { JavaMethod method ; if ( ja instanceof JavaMethod ) { method = ( JavaMethod ) ja ; } else { throw new RuntimeException ( "Action can only annotate JavaMethod" ) ; } boolean required = false ; JavaInterface intf = method . getInterface ( ) ; MessageInfo inputMessage = operation . getInput ( ) ; MessageInfo outputMessage = operation . getOutput ( ) ; JAnnotation actionAnnotation = new JAnnotation ( Action . class ) ; if ( inputMessage . getExtensionAttributes ( ) != null ) { String inputAction = getAction ( inputMessage ) ; if ( inputAction != null ) { actionAnnotation . addElement ( new JAnnotationElement ( "input" , inputAction ) ) ; required = true ; } } if ( outputMessage != null && outputMessage . getExtensionAttributes ( ) != null ) { String outputAction = getAction ( outputMessage ) ; if ( outputAction != null ) { actionAnnotation . addElement ( new JAnnotationElement ( "output" , outputAction ) ) ; required = true ; } } if ( operation . hasFaults ( ) ) { List < JAnnotation > faultAnnotations = new ArrayList < JAnnotation > ( ) ; for ( FaultInfo faultInfo : operation . getFaults ( ) ) { if ( faultInfo . getExtensionAttributes ( ) != null ) { String faultAction = getAction ( faultInfo ) ; if ( faultAction == null ) { continue ; } JavaException exceptionClass = getExceptionClass ( method , faultInfo ) ; if ( ! StringUtils . isEmpty ( exceptionClass . getPackageName ( ) ) && ! exceptionClass . getPackageName ( ) . equals ( intf . getPackageName ( ) ) ) { intf . addImport ( exceptionClass . getClassName ( ) ) ; } JAnnotation faultAnnotation = new JAnnotation ( FaultAction . class ) ; faultAnnotation . addElement ( new JAnnotationElement ( "className" , exceptionClass ) ) ; faultAnnotation . addElement ( new JAnnotationElement ( "value" , faultAction ) ) ; faultAnnotations . add ( faultAnnotation ) ; required = true ; } } actionAnnotation . addElement ( new JAnnotationElement ( "fault" , faultAnnotations ) ) ; } if ( required ) { method . addAnnotation ( "Action" , actionAnnotation ) ; } } private JavaException getExceptionClass ( JavaMethod method , FaultInfo faultInfo ) { for ( JavaException exception : method . getExceptions ( ) ) { QName faultName = faultInfo . getName ( ) ; if ( exception . getTargetNamespace ( ) . equals ( faultName . getNamespaceURI ( ) ) && exception . getName ( ) . toLowerCase ( ) . startsWith ( faultName . getLocalPart ( ) . toLowerCase ( ) ) ) { return exception ; } } return null ; } }